import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Quote: empty and basics
  it("empty item list → premium 5 G (only processing fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result.results[0]).toEqual({ premium: 5 });
  });
  it("single sword → premium 105 G (100 base + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 3, cursed: false }],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 105 });
  });
  it("single amulet → premium 65 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "amulet", material: "silver", enchantment: 2, cursed: false }],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 65 });
  });
  it.todo("single staff → premium 85 G");
  it.todo("single potion → premium 45 G");
  it.todo("single rune (component) → premium 30 G (25 + 5)");
  it.todo("two items (sword + amulet) → premium 165 G (100 + 60 + 5)");

  // Component block
  it.todo("3 runes → premium 65 G (block discount: 60 + 5)");
  it.todo("2 runes → premium 55 G (no block: 50 + 5)");
  it.todo("4 runes → premium 105 G (no block: 100 + 5)");
  it.todo("3 runes + 3 moonstones → premium 125 G (two blocks: 60+60+5)");

  // Item-level modifiers
  it.todo("cursed sword → premium 155 G (100 + 50 curse + 5)");
  it.todo("highly enchanted sword (enchantment 5) → premium 135 G (100 + 30 + 5)");
  it.todo("cursed sword enchantment 5 → premium 185 G (100+50+30+5)");

  // Policy-level modifiers
  it.todo("first insurance surcharge: sword for new customer → 115 G (100 + 10 + 5)");
  it.todo("loyalty discount: sword for 2-year customer → 85 G (100 - 20 + 5)");
  it.todo("follow-up contract discount on second quote: sword → 90 G (100 - 15 + 5)");

  // Rounding
  it.todo("premium rounding up: a result with 0.5 is rounded up in MHPCO favor");

  // Integration examples from spec
  it.todo("newcomer cursed sword (enchantment 3) → premium 165 G");
  it.todo("3-year customer second contract cursed sword enchantment 7 → premium 160 G");

  // Claim basics
  it.todo("standard sword damage 500 G → payout 400 G, remainingCap 1600 G");
  it.todo("rune damage 200 G → payout 100 G");
  it.todo("dragon material sword enchantment 5 damage 800 → payout 700");
  it.todo("high-enchantment (enchantment 8) sword damage 1000 → payout 400");
  it.todo("dragon material sword enchantment 9 damage 1000 → payout 400 (50% wins)");
  it.todo("two swords damaged in one event → each deductible applied separately");
  it.todo("cap exhaustion: two 1500 claims on sword (cap 2000) → 1400 then 600");

  // Errors
  it.todo("unknown item type in quote → CLI exits non-zero");
  it.todo("claim references item not in policy → CLI exits non-zero");
  it.todo("claim with negative damage amount → CLI exits non-zero");
  it.todo("more damage entries of a type than policy covers → CLI exits non-zero");
});

