export interface Item {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
}

export interface QuoteStep {
  op: "quote";
  items: Item[];
}

export type Step = QuoteStep;

export interface Scenario {
  customer: { yearsWithMHPCO: number };
  steps: Step[];
}

export interface QuoteResult {
  premium: number;
}

export interface ScenarioResult {
  results: QuoteResult[];
}

const PROCESSING_FEE = 5;

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

const basePremiumFor = (item: Item): number => BASE_PREMIUM[item.type] ?? 0;

const COMPONENT_TYPES = new Set(["rune"]);
const COMPONENT_BLOCK_SIZE = 3;
const COMPONENT_BLOCK_PRICE = 60;

const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);

const componentsCost = (components: Item[]): number =>
  components.length === COMPONENT_BLOCK_SIZE
    ? COMPONENT_BLOCK_PRICE
    : components.reduce((sum, item) => sum + basePremiumFor(item), 0);

const sumBasePremiums = (items: Item[]): number => {
  const [components, nonComponents] = partition(items, isComponent);
  const nonComponentsCost = nonComponents.reduce(
    (sum, item) => sum + basePremiumFor(item),
    0,
  );
  return componentsCost(components) + nonComponentsCost;
};

const partition = <T>(
  items: T[],
  predicate: (item: T) => boolean,
): [T[], T[]] => {
  const matching: T[] = [];
  const rest: T[] = [];
  for (const item of items) {
    (predicate(item) ? matching : rest).push(item);
  }
  return [matching, rest];
};

const quote = (items: Item[]): QuoteResult => ({
  premium: sumBasePremiums(items) + PROCESSING_FEE,
});

export const runScenario = (scenario: Scenario): ScenarioResult => ({
  results: scenario.steps.map((step) => quote(step.items)),
});

