export interface Item {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
}

export interface QuoteStep {
  op: "quote";
  items: Item[];
}

export type Step = QuoteStep;

export interface Scenario {
  customer: { yearsWithMHPCO: number };
  steps: Step[];
}

export interface QuoteResult {
  premium: number;
}

export interface ScenarioResult {
  results: QuoteResult[];
}

const PROCESSING_FEE = 5;

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const basePremiumFor = (item: Item): number => BASE_PREMIUM[item.type] ?? 0;

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const COMPONENT_BLOCK_SIZE = 3;
const COMPONENT_BLOCK_PRICE = 60;

const groupByType = (items: Item[]): Map<string, Item[]> => {
  const groups = new Map<string, Item[]>();
  for (const item of items) {
    const group = groups.get(item.type) ?? [];
    group.push(item);
    groups.set(item.type, group);
  }
  return groups;
};

const groupCost = (type: string, group: Item[]): number => {
  if (
    COMPONENT_TYPES.has(type) &&
    group.length === COMPONENT_BLOCK_SIZE
  ) {
    return COMPONENT_BLOCK_PRICE;
  }
  return group.reduce((sum, item) => sum + basePremiumFor(item), 0);
};

const itemsSubtotal = (items: Item[]): number => {
  let total = 0;
  for (const [type, group] of groupByType(items)) {
    total += groupCost(type, group);
  }
  return total;
};

const quote = (items: Item[]): QuoteResult => ({
  premium: itemsSubtotal(items) + PROCESSING_FEE,
});

export const runScenario = (scenario: Scenario): ScenarioResult => ({
  results: scenario.steps.map((step) => quote(step.items)),
});

