interface Policy {
  items: Item[];
  insuranceSum: number;
  remainingCap: number;
}

const policyInsuranceSum = (items: Item[]): number =>
  items.reduce((sum, item) => sum + (INSURANCE_VALUE[item.type] ?? 0), 0);

const createPolicy = (items: Item[]): Policy => {
  const insuranceSum = policyInsuranceSum(items);
  return {
    items,
    insuranceSum,
    remainingCap: insuranceSum * CAP_MULTIPLIER,
  };
};

const processClaim = (policy: Policy, step: ClaimStep): ClaimResult => {
  const payout = step.incident.damages.reduce(
    (sum, damage) => sum + Math.max(0, damage.amount - DEDUCTIBLE),
    0,
  );
  policy.remainingCap -= payout;
  return { payout, remainingCap: policy.remainingCap };
};

export const runScenario = (scenario: Scenario): ScenarioResult => {
  const policies: Policy[] = [];
  let quoteCount = 0;
  const results: StepResult[] = scenario.steps.map((step) => {
    if (step.op === "quote") {
      const isFollowUp = quoteCount > 0;
      quoteCount += 1;
      policies.push(createPolicy(step.items));
      return quote(step.items, scenario.customer, isFollowUp);
    }
    return processClaim(policies[step.policy], step);
  });
  return { results };
};

